const { exec } = require('child_process');
const https = require('https');

const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const ALLOWED_USER_ID = process.env.TELEGRAM_USER_ID; // 你的 Telegram User ID

// 白名单命令
const ALLOWED_COMMANDS = {
  'sync': 'pnpm sync:telegram',
  'dev': 'pnpm dev',
  'build': 'pnpm build',
  'status': 'git status',
  'log': 'git log --oneline -5',
  'pull': 'git pull',
  'help': 'echo "可用命令: sync, dev, build, status, log, pull, help"'
};

let offset = 0;

function sendMessage(chatId, text) {
  const data = JSON.stringify({ chat_id: chatId, text });
  const options = {
    hostname: 'api.telegram.org',
    path: `/bot${BOT_TOKEN}/sendMessage`,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' }
  };

  const req = https.request(options);
  req.write(data);
  req.end();
}

function executeCommand(cmd) {
  return new Promise((resolve) => {
    exec(cmd, { cwd: __dirname + '/..', timeout: 30000 }, (err, stdout, stderr) => {
      if (err) resolve(`❌ 错误: ${err.message}`);
      else resolve(stdout || stderr || '✅ 执行完成');
    });
  });
}

async function processUpdate(update) {
  const msg = update.message;
  if (!msg || !msg.text) return;

  const chatId = msg.chat.id;
  const userId = msg.from.id;
  const text = msg.text.trim();

  // 验证用户
  if (String(userId) !== String(ALLOWED_USER_ID)) {
    sendMessage(chatId, '⛔️ 未授权');
    return;
  }

  // 处理命令
  if (text.startsWith('/')) {
    const cmd = text.slice(1).toLowerCase();

    if (ALLOWED_COMMANDS[cmd]) {
      sendMessage(chatId, `⏳ 执行中: ${cmd}`);
      const result = await executeCommand(ALLOWED_COMMANDS[cmd]);
      sendMessage(chatId, result.slice(0, 4000)); // Telegram 限制
    } else {
      sendMessage(chatId, '❓ 未知命令，发送 /help 查看可用命令');
    }
  }
}

async function pollUpdates() {
  try {
    const url = `https://api.telegram.org/bot${BOT_TOKEN}/getUpdates?offset=${offset}&timeout=30`;
    const res = await fetch(url);
    const data = await res.json();

    if (data.ok && data.result.length > 0) {
      for (const update of data.result) {
        await processUpdate(update);
        offset = update.update_id + 1;
      }
    }
  } catch (err) {
    console.error('Poll error:', err.message);
  }

  setTimeout(pollUpdates, 1000);
}

console.log('🤖 Telegram CLI Bot 启动...');
pollUpdates();

