import Anthropic from '@anthropic-ai/sdk';
import { exec } from 'child_process';
import fs from 'fs/promises';
import https from 'https';
import path from 'path';
import { promisify } from 'util';

const execAsync = promisify(exec);

const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const ALLOWED_USER_ID = process.env.TELEGRAM_USER_ID;
const CLAUDE_API_KEY = process.env.ANTHROPIC_API_KEY;

const client = new Anthropic({ apiKey: CLAUDE_API_KEY });
const PROJECT_ROOT = path.join(process.cwd());

let offset = 0;
const conversations = new Map(); // 存储对话历史

function sendMessage(chatId, text) {
  const data = JSON.stringify({
    chat_id: chatId,
    text,
    parse_mode: 'Markdown'
  });

  const options = {
    hostname: 'api.telegram.org',
    path: `/bot${BOT_TOKEN}/sendMessage`,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' }
  };

  const req = https.request(options);
  req.write(data);
  req.end();
}

async function readFile(filePath) {
  try {
    const fullPath = path.join(PROJECT_ROOT, filePath);
    return await fs.readFile(fullPath, 'utf8');
  } catch {
    return null;
  }
}

async function writeFile(filePath, content) {
  try {
    const fullPath = path.join(PROJECT_ROOT, filePath);
    await fs.writeFile(fullPath, content, 'utf8');
    return true;
  } catch {
    return false;
  }
}

const tools = [
  {
    name: 'read_file',
    description: '读取项目文件内容',
    input_schema: {
      type: 'object',
      properties: {
        file_path: { type: 'string', description: '相对于项目根目录的文件路径' }
      },
      required: ['file_path']
    }
  },
  {
    name: 'write_file',
    description: '写入或修改项目文件',
    input_schema: {
      type: 'object',
      properties: {
        file_path: { type: 'string', description: '文件路径' },
        content: { type: 'string', description: '文件内容' }
      },
      required: ['file_path', 'content']
    }
  },
  {
    name: 'execute_command',
    description: '执行 shell 命令（限制：git, pnpm, ls, cat）',
    input_schema: {
      type: 'object',
      properties: {
        command: { type: 'string', description: '要执行的命令' }
      },
      required: ['command']
    }
  }
];

async function handleToolUse(toolName, toolInput) {
  switch (toolName) {
    case 'read_file':
      const content = await readFile(toolInput.file_path);
      return content || '文件不存在或无法读取';

    case 'write_file':
      const success = await writeFile(toolInput.file_path, toolInput.content);
      return success ? '✅ 文件已更新' : '❌ 写入失败';

    case 'execute_command':
      const cmd = toolInput.command;
      if (!/^(git|pnpm|ls|cat|pwd)/.test(cmd)) {
        return '❌ 不允许的命令';
      }
      try {
        const { stdout } = await execAsync(cmd, { cwd: PROJECT_ROOT, timeout: 30000 });
        return stdout;
      } catch (err) {
        return `❌ ${err.message}`;
      }

    default:
      return '未知工具';
  }
}

