async function chatWithClaude(chatId, userMessage) {
  let history = conversations.get(chatId) || [];

  history.push({
    role: 'user',
    content: userMessage
  });

  const systemPrompt = `你是 kkdemian 的 AI 助手，通过 Telegram 帮助管理 portfolio 项目。

项目信息：
- Next.js 16 + TypeScript + Tailwind
- 位置：${PROJECT_ROOT}
- 主要目录：src/app, src/components, content/blog

你可以：
1. 读取和修改项目文件
2. 执行 git/pnpm 命令
3. 回答技术问题

规则：
- 简洁直接，中文回答
- 修改文件前先读取
- 重要操作前说明原因`;

  try {
    let response = await client.messages.create({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 4096,
      system: systemPrompt,
      tools,
      messages: history
    });

    // 处理工具调用循环
    while (response.stop_reason === 'tool_use') {
      const toolUse = response.content.find(block => block.type === 'tool_use');

      if (toolUse) {
        const result = await handleToolUse(toolUse.name, toolUse.input);

        history.push({
          role: 'assistant',
          content: response.content
        });

        history.push({
          role: 'user',
          content: [{
            type: 'tool_result',
            tool_use_id: toolUse.id,
            content: result
          }]
        });

        response = await client.messages.create({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 4096,
          system: systemPrompt,
          tools,
          messages: history
        });
      } else {
        break;
      }
    }

    const finalText = response.content
      .filter(block => block.type === 'text')
      .map(block => block.text)
      .join('\n');

    history.push({
      role: 'assistant',
      content: finalText
    });

    // 保留最近 10 轮对话
    if (history.length > 20) {
      history = history.slice(-20);
    }

    conversations.set(chatId, history);

    return finalText || '处理完成';
  } catch (err) {
    return `❌ AI 错误: ${err.message}`;
  }
}

